    rm -rf "/Applications/Thaw.app" 2>/dev/null || true
elif [ -f "/Applications/Thaw.app" ]; then
    rm -f "/Applications/Thaw.app" 2>/dev/null || true
fi

# Remove $HOME/Library/Caches/com.stonerl.Thaw
